using Microsoft.AspNetCore.Mvc;
using System.Net.Http;
using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class WebhookProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public WebhookProxyController(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [HttpPost("{*path}")]
    public async Task<IActionResult> Proxy([FromRoute] string path, [FromBody] object body)
    {
        if (string.IsNullOrEmpty(path))
            return BadRequest("Path is required");

        try
        {
            var requestUrl = path.StartsWith("http") ? path : $"https://{path}";
            
            using var request = new HttpRequestMessage(HttpMethod.Post, requestUrl);
            
            if (body != null)
            {
                var json = System.Text.Json.JsonSerializer.Serialize(body);
                request.Content = new StringContent(json, System.Text.Encoding.UTF8, "application/json");
            }

            var response = await _httpClient.SendAsync(request);
            
            var responseContent = await response.Content.ReadAsStringAsync();
            
            return new ContentResult
            {
                Content = responseContent,
                StatusCode = (int)response.StatusCode,
                ContentType = response.Content.Headers.ContentType?.ToString()
            };
        }
        catch (Exception ex)
        {
            return StatusCode(500, ex.Message);
        }
    }
}